import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useChat } from '../context/ChatContext';
import { getUsers } from '../api';
import './UsersListPage.css';

const UsersListPage = () => {
  const [users, setUsers] = useState([]);
  const [filter, setFilter] = useState(null); // null = all, 'Male', 'Female'
  const [loading, setLoading] = useState(false);
  const { user } = useAuth();
  const { setSelectedUser, onlineUsers } = useChat();
  const navigate = useNavigate();

  useEffect(() => {
    fetchUsers();
  }, [filter, user]);

  // Update online status when onlineUsers changes from socket
  useEffect(() => {
    if (users.length > 0) {
      setUsers(prev => prev.map(u => ({
        ...u,
        isOnline: onlineUsers.some(ou => ou._id === u._id)
      })));
    }
  }, [onlineUsers]); // eslint-disable-line react-hooks/exhaustive-deps

  const fetchUsers = async () => {
    if (!user) return;
    setLoading(true);
    try {
      const data = await getUsers(filter, user._id);
      const usersWithOnlineStatus = data.map(u => ({
        ...u,
        isOnline: onlineUsers.some(ou => ou._id === u._id)
      }));
      setUsers(usersWithOnlineStatus);
    } catch (error) {
      console.error('Error fetching users:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleChat = (selectedUser) => {
    setSelectedUser({
      _id: selectedUser._id,
      nickname: selectedUser.nickname,
      gender: selectedUser.gender
    });
    navigate('/chat');
  };

  return (
    <div className="users-list-page">
      <div className="users-header">
        <h1>Find Users</h1>
        <div className="filter-buttons">
          <button 
            className={`filter-btn ${filter === null ? 'active' : ''}`}
            onClick={() => setFilter(null)}
          >
            All
          </button>
          <button 
            className={`filter-btn male ${filter === 'Male' ? 'active' : ''}`}
            onClick={() => setFilter('Male')}
          >
            👨 Males
          </button>
          <button 
            className={`filter-btn female ${filter === 'Female' ? 'active' : ''}`}
            onClick={() => setFilter('Female')}
          >
            👩 Females
          </button>
        </div>
      </div>

      {loading ? (
        <div className="loading">Loading users...</div>
      ) : (
        <div className="users-grid">
          {users.length === 0 ? (
            <div className="no-users">No users found</div>
          ) : (
            users.map(u => (
              <div key={u._id} className={`user-card ${u.gender?.toLowerCase()}`}>
                <div className="user-card-avatar">
                  {u.nickname?.charAt(0).toUpperCase()}
                  {u.isOnline && <span className="online-dot"></span>}
                </div>
                <div className="user-card-info">
                  <h3>{u.nickname}</h3>
                  <span className={`gender-tag ${u.gender?.toLowerCase()}`}>
                    {u.gender === 'Male' ? '👨' : '👩'} {u.gender}
                  </span>
                  <span className={`status ${u.isOnline ? 'online' : 'offline'}`}>
                    {u.isOnline ? '🟢 Online' : '⚫ Offline'}
                  </span>
                </div>
                <button 
                  className="chat-btn"
                  onClick={() => handleChat(u)}
                >
                  💬 Chat
                </button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default UsersListPage;
